const chatInput = ($input.first().json.chatInput || '').trim();
if (chatInput.length > 5000) throw new Error('Input too long (max 5000 chars): ' + chatInput.length);

const inputType = chatInput.length > 500 ? 'full_story' : 'theme';

const universeId = 'univ-' + Date.now().toString(36) + '-' + Math.random().toString(36).substring(2, 8);

const wordSet = new Set(chatInput.toLowerCase().split(/[\s,.'!?;:()\-]+/).filter(Boolean));

const settingKeywords = {
  'forêt': { color: '#228B22', emoji: '🌲', setting: 'forêt' },
  'forest': { color: '#228B22', emoji: '🌲', setting: 'forêt' },
  'océan': { color: '#1E90FF', emoji: '🌊', setting: 'océan' },
  'mer': { color: '#1E90FF', emoji: '🌊', setting: 'mer' },
  'ocean': { color: '#1E90FF', emoji: '🌊', setting: 'océan' },
  'espace': { color: '#191970', emoji: '🚀', setting: 'espace' },
  'space': { color: '#191970', emoji: '🚀', setting: 'espace' },
  'volcan': { color: '#FF4500', emoji: '🌋', setting: 'volcan' },
  'montagne': { color: '#8B4513', emoji: '⛰️', setting: 'montagne' },
  'château': { color: '#DAA520', emoji: '🏰', setting: 'château' },
  'castle': { color: '#DAA520', emoji: '🏰', setting: 'château' },
  'pirate': { color: '#2F4F4F', emoji: '🏴‍☠️', setting: 'pirate' },
  'dragon': { color: '#B22222', emoji: '🐉', setting: 'dragon' },
  'école': { color: '#FF69B4', emoji: '🏫', setting: 'école' },
  'jardin': { color: '#90EE90', emoji: '🌸', setting: 'jardin' },
  'désert': { color: '#DEB887', emoji: '🏜️', setting: 'désert' },
  'neige': { color: '#B0E0E6', emoji: '❄️', setting: 'neige' },
  'glace': { color: '#B0E0E6', emoji: '❄️', setting: 'glace' },
};

let detectedSetting = { color: '#6B7DB3', emoji: '📖', setting: 'aventure' };
for (const [kw, meta] of Object.entries(settingKeywords)) {
  if (wordSet.has(kw) || chatInput.toLowerCase().includes(kw)) {
    detectedSetting = meta;
    break;
  }
}

return [{
  json: {
    chatInput,
    inputType,
    universeId,
    detectedSetting,
  }
}];

const item = $input.first().json;
const base = 'https://wddatxgqhdiosuhcztex.supabase.co/rest/v1/avatars';
const url = base + '?select=character_name,character_prompt,gender';

return [{ json: {
  chatInput: item.chatInput,
  inputType: item.inputType,
  universeId: item.universeId,
  detectedSetting: item.detectedSetting,
  avatarFetchUrl: url
} }];

const items = $input.all();
const rows = [];
items.forEach(i => {
  const j = i.json;
  if (Array.isArray(j)) rows.push(...j);
  else if (j && typeof j === 'object' && (j.character_name != null || j.body != null)) {
    if (Array.isArray(j.body)) rows.push(...j.body);
    else rows.push(j);
  }
});

const allAvatars = {};
let firstGender = 'girl';
rows.forEach(r => {
  if (r.character_name) {
    allAvatars[r.character_name.toLowerCase()] = {
      name: r.character_name,
      prompt: r.character_prompt || '(apparence à définir selon le contexte)',
      gender: r.gender || 'girl'
    };
    if (!firstGender || firstGender === 'girl') firstGender = r.gender || 'girl';
  }
});

let analyzeData = {};
try { analyzeData = $('Analyze Input').first().json; } catch(e) {}
const chatInput = (analyzeData.chatInput || '').toLowerCase();

const matched = {};
for (const [key, avatar] of Object.entries(allAvatars)) {
  if (chatInput.includes(key)) {
    matched[avatar.name] = avatar.prompt;
    firstGender = avatar.gender;
  }
}

if (Object.keys(matched).length === 0) {
  const fallbackKey = Object.keys(allAvatars)[0];
  if (fallbackKey) {
    const fb = allAvatars[fallbackKey];
    matched[fb.name] = fb.prompt;
    firstGender = fb.gender;
  }
}

const characterBible = Object.entries(matched)
  .map(([name, prompt]) => name + ': ' + prompt)
  .join('\n');

const fallback = 'Hana: fillette de 8 ans, cheveux noirs courts au carré, petit ruban rouge côté gauche, grands yeux vert émeraude, tunique bleue aventurière bordures dorées, bottes cuir marron, pendentif étoile lumineux.';

return [{ json: {
  characterBible: characterBible || fallback,
  avatarGender: firstGender,
  characterCount: Object.keys(matched).length,
  matchedCharacters: Object.keys(matched),
  availableCharacters: Object.keys(allAvatars).map(k => allAvatars[k].name)
} }];

const merge = $('Merge chatInput + character bible').first().json;
const storyInput = (merge.chatInput || '').trim();
const characterBible = merge.characterBible || '';
const universeId = merge.universeId || 'univ-fallback';
const detectedSetting = merge.detectedSetting || { setting: 'aventure' };
const inputType = merge.inputType || 'theme';

const taskBlock = inputType === 'full_story'
  ? '- L\'utilisateur a fourni un texte complet. Découpe-le en exactement 5 pages narratives.\n- Conserve le récit original tout en l\'adaptant au format interactif.'
  : '- L\'utilisateur a fourni un thème ou synopsis. Invente une histoire originale de 5 pages.\n- Crée un arc narratif avec début, péripéties et dénouement.';

const fullPrompt = `Tu es un adaptateur narratif manga pour enfants (6-10 ans). Tu crées une histoire interactive structurée en JSON.

BIBLE VISUELLE DES PERSONNAGES (RESPECTER STRICTEMENT) :
${characterBible}

ENTRÉE UTILISATEUR :
${storyInput || '(aucun thème fourni - invente une aventure courte adaptée aux personnages)'}

IDENTIFIANT UNIVERS PRÉ-GÉNÉRÉ (OBLIGATOIRE - utiliser tel quel) :
${universeId}

TÂCHE :
${taskBlock}
- Chaque page sauf la dernière a 2 choix interactifs.
- La dernière page conclut l'histoire (choices = []).
- Langue : français correct, phrases simples, max 15 mots par phrase.

CONTRAINTES PANELS :
- Panels = descriptions visuelles PURES. JAMAIS de texte, dialogue, bulle, titre.
- Décrire uniquement ce qu'on VOIT : décor, personnages, actions, expressions.
- Les personnages doivent correspondre EXACTEMENT à la bible visuelle.
- 2-4 panels par page selon la densité narrative.

CONTRAINTES scene_summary :
- Description orientée génération d'image.
- Inclure : lieu, ambiance, éclairage, personnages présents, action principale.

FORMAT DE SORTIE : JSON strict uniquement. Pas de markdown.

SCHÉMA :
{
  \"universe\": { \"id\": \"${universeId}\", \"name\": \"string\", \"description\": \"1 phrase\", \"image_url\": \"\", \"color\": \"#hex\", \"emoji\": \"emoji\", \"gender\": \"girl|boy\", \"display_order\": 1 },
  \"story_starts\": [{ \"id\": \"start-NNN\", \"title\": \"max 6 mots\", \"text\": \"accroche max 15 mots\", \"paragraph_text\": \"intro 2-3 phrases\", \"scene_summary\": \"description visuelle intro\" }],
  \"pages\": [{ \"universe_id\": \"${universeId}\", \"page_number\": 1, \"paragraph_text\": \"2-4 phrases\", \"scene_summary\": \"description visuelle\", \"panels\": [{ \"panel_number\": 1, \"camera_angle\": \"plan large|moyen|gros plan\", \"description\": \"visuel pur\" }], \"choices\": [{ \"id\": \"choice-pN-a\", \"text\": \"max 10 mots\" }] }]
}

RÈGLES :
- universe.id ET chaque page.universe_id = \"${universeId}\" (pré-généré, ne pas changer).
- page_number séquentiel 1 à 5.
- choice.id uniques (choice-pN-a, choice-pN-b).
- story_starts.id uniques (start-NNN).
- 2-3 story_starts avec accroches différentes de la page 1.`;

return [{ json: { fullPrompt, characterBible, universeId, detectedSetting, inputType } }];

const raw = $input.first().json?.output?.[0]?.content?.[0]?.text;
if (!raw) throw new Error('No LLM output received. Check Generate story JSON node.');

let cleaned = raw.trim();
if (cleaned.startsWith('```')) {
  cleaned = cleaned.replace(/```json/g, '').replace(/```/g, '').trim();
}

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (e) {
  throw new Error('LLM returned invalid JSON: ' + e.message + ' | First 300 chars: ' + cleaned.substring(0, 300));
}

const pages = parsed.pages || [parsed.page];
if (!pages || pages.length === 0) throw new Error('No pages found in LLM output.');

let preGenUniverseId = '';
let detectedSetting = { color: '#6B7DB3', emoji: '📖' };
let characterBible = '';
let avatarGender = 'girl';
try {
  const promptData = $('Build story prompt with bible').first().json;
  preGenUniverseId = promptData.universeId || '';
  detectedSetting = promptData.detectedSetting || detectedSetting;
  characterBible = promptData.characterBible || '';
} catch (e) {}
try {
  const m = $('Merge chatInput + character bible').first().json;
  avatarGender = m.avatarGender || 'girl';
} catch (e) {}

const universeId = preGenUniverseId || (parsed.universe && parsed.universe.id) || 'univ-fallback';

const universe = parsed.universe
  ? { ...parsed.universe, id: universeId, color: parsed.universe.color || detectedSetting.color, emoji: parsed.universe.emoji || detectedSetting.emoji }
  : { id: universeId, name: 'Univers généré', description: '', image_url: '', color: detectedSetting.color, emoji: detectedSetting.emoji, gender: avatarGender, display_order: 1 };

const BUCKET = 'BD-Pages';
const SUPABASE_URL = 'https://wddatxgqhdiosuhcztex.supabase.co';
const now = new Date().toISOString();

const CHARACTER_LOCK = characterBible
  ? '\nCharacter reference (STRICT - MUST remain identical in every image):\n\n' + characterBible + '\n\nDO NOT change character design.\n'
  : '\nMain character: 8-year-old girl, short black bob, red ribbon left, emerald eyes, blue tunic, brown boots. DO NOT change design.\n';

return pages.map(page => {
  const pageNumber = page.page_number;
  if (!pageNumber) throw new Error('Page missing page_number: ' + JSON.stringify(page).substring(0, 200));
  const fileName = `${universeId}-page-${pageNumber}.png`;
  const storagePath = `${universeId}/${fileName}`;

  return {
    json: {
      universe,
      universeId,
      pageNumber,
      paragraphText: page.paragraph_text,
      sceneSummary: page.scene_summary,
      panels: page.panels,
      choices: page.choices || [],
      storyStarts: parsed.story_starts || [],
      avatarGender,
      bucket: BUCKET,
      fileName,
      storagePath,
      supabaseUrl: SUPABASE_URL,
      createdAt: now,
      geminiPrompt: `Create a full children manga page illustration.\n\nSTYLE:\nSoft pastel Japanese children manga style.\nNo text. No speech bubbles. No typography. No watermark. No title.\n\n${CHARACTER_LOCK}\n\nSCENE:\n${page.scene_summary}\n\nPANELS:\n${JSON.stringify(page.panels, null, 2)}\n\nIMPORTANT:\n- Maintain strict character consistency across all pages.\n- No text or writing anywhere in the image.\n- Child-safe content only.`
    }
  };
});

const item = $input.first().json;
const u = item.universe;
if (!u || !u.id) {
  console.log('No universe data found, skipping upsert');
  return [];
}
const gender = item.avatarGender || u.gender || 'girl';
return [{
  json: {
    id: u.id,
    name: u.name || 'Unnamed Universe',
    description: u.description || '',
    image_url: u.image_url || '',
    color: u.color || '#6B7DB3',
    emoji: u.emoji || '📖',
    gender: gender,
    display_order: u.display_order || 1
  }
}];

const parseItem = $('Parse story JSON').first().json;
const starts = parseItem.storyStarts || [];
const universeId = parseItem.universeId;

if (!starts.length || !universeId) {
  console.log('No story_starts or missing universeId, skipping');
  return [];
}

return starts.map(s => ({
  json: {
    id: s.id || `start-${Math.random().toString(36).substring(2, 8)}`,
    universe_id: universeId,
    title: s.title || 'Sans titre',
    text: s.text || '',
    paragraph_text: s.paragraph_text || '',
    scene_summary: s.scene_summary || ''
  }
}));

const items = $input.all();
return items.filter(item => item.json.universeId && item.json.pageNumber).map(item => ({
  json: {
    universe_id: item.json.universeId,
    page_number: item.json.pageNumber,
    text: item.json.paragraphText || '',
    scene_summary: item.json.sceneSummary || '',
    image_url: `${item.json.supabaseUrl}/storage/v1/object/public/${item.json.bucket}/${item.json.storagePath}`,
    created_at: item.json.createdAt
  }
}));

const items = $input.all();
const results = [];
for (const item of items) {
  if (!item.json.universeId || !item.json.pageNumber) continue;
  const choices = item.json.choices || [];
  choices.forEach((choice, index) => {
    results.push({
      json: {
        id: choice.id || `choice-p${item.json.pageNumber}-${String.fromCharCode(97 + index)}`,
        universe_id: item.json.universeId,
        page_number: item.json.pageNumber,
        choice_order: index + 1,
        text: choice.text || '',
        created_at: item.json.createdAt
      }
    });
  });
}
return results;
